const rows = $input.all();

let day = Number($now.toFormat('d'));

if (day > 30) day = 30; 

const match = rows.find(r => Number(r.json.Day) === day);

if (!match) throw new Error(`No row found for Day=${day}`);
return [match];

let p = $input.first().json;
if (Array.isArray(p)) p = p[0] || {};

const raw = String(p?.choices?.[0]?.message?.content || "");

const citations = Array.isArray(p?.citations) ? p.citations : [];

const searchResults = Array.isArray(p?.search_results) ? p.search_results : [];

const row = $("Fetch Theme").first().json;

const subject = row["Subject Hook"] || "Daily Investor Brief";
const theme = row.Theme || "";
const business  = row["business  Block"] || "";
const cta = row.CTA || "Reply with your county";

const BRAND = {
  name: "business name",
  site: "https://business data.io",
  contact: "https://business data.io/contact/",
  trialCode: "business DATA",
  email: "contact@business data.io",
  phone: "(409) 240-9010",
  logoUrl:
    "https://i0.wp.com/business data.io/wp-content/uploads/2022/08/cropped-revamped-logo-2.png?fit=715%2C104&ssl=1",
  signatureName: "business Data Team",
  signatureTitle: "business name",
  profileImg: "https://business data.io/wp-content/uploads/2021/08/cropped-cropped-Asset-6.png",

  youtube: "https://www.youtube.com/@realestate-data-tech/featured",
  instagram: "https://www.instagram.com/business data/",
  skool: "https://www.skool.com/realestate-data-tech-leads",
};

const NAVY = "#0b2a6f";
const BLUE = "#1a73e8";
const BORDER = "#e6e6e6";
const MUTED = "#5f6368";
const BG = "#f3f4f6";
const EDGE_BG = "#eef3ff";
const RED = "#ff3b30";

const esc = (s) =>
  String(s || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

const stripMarkdown = (s) =>
  String(s || "")
    .replace(/\[(\d+)\]/g, "") // [1]
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .replace(/^\s{0,3}#{1,6}\s*/gm, "")
    .replace(/^\s{0,3}---\s*$/gm, "")
    .replace(/\s+/g, " ")
    .trim();

const trimLen = (s, n) => {
  const t = stripMarkdown(s);
  return t.length > n ? t.slice(0, n).trim() + "..." : t;
};

const topBarHtml = `
  <div style="background:${NAVY}; color:#ffffff; padding:12px 14px; text-align:center; font-family:Arial, sans-serif;">
    <span style="font-size:13px; line-height:1.5;">
      Use discount code
      <span style="font-weight:900; font-size:17px; color:${RED};">${BRAND.trialCode}</span>
      at checkout for a <b>7-day Free trial</b> coupon for you to try our service.
    </span>
  </div>
`;

let intro = stripMarkdown(raw);
if (intro.length > 550) intro = intro.slice(0, 550).trim() + "...";
if (!intro) intro = "Here are the key real estate signals from the last 24–48 hours.";

let items = [];

if (searchResults.length) {
  items = searchResults
    .filter((r) => r && (r.title || r.url))
    .slice(0, 5)
    .map((r) => ({
      title: r.title || "Market Update",
      body: r.snippet || "Click to read the source.",
      link: r.url || "",
    }));
} else if (citations.length) {
  items = citations.slice(0, 5).map((u) => ({
    title: "Source",
    body: u,
    link: u,
  }));
} else {
  items = [
    {
      title: "Today’s Market Pulse",
      body: raw,
      link: "",
    },
  ];
}

const itemCards = items
  .map((it) => {
    const title = esc(stripMarkdown(it.title));
    const body = esc(trimLen(it.body || "", 240));
    const link = it.link || "";

    const button = link
      ? `<a href="${link}" target="_blank"
          style="display:inline-block; margin-top:10px; background:${BLUE}; color:#fff; text-decoration:none; padding:10px 14px; border-radius:10px; font-weight:700;">
          Read more
        </a>`
      : "";

    return `
      <div style="border:1px solid ${BORDER}; border-radius:16px; padding:16px; margin:14px 0; background:#fff;">
        <div style="font-size:18px; font-weight:900; margin:0 0 8px;">${title}</div>
        <div style="font-size:14px; color:${MUTED}; line-height:1.6;">${body}</div>
        ${button}
      </div>
    `;
  })
  .join("");

const business Box = `
  <table role="presentation" width="100%" cellpadding="0" celbusiness acing="0" style="margin:18px 0;">
    <tr>
      <td style="border:1px solid ${BORDER}; border-radius:16px; overflow:hidden; font-family:Arial, sans-serif;">

        <!-- Header -->
        <div style="background:${NAVY}; color:#fff; padding:12px 14px;">
          <div style="font-size:12px; letter-spacing:0.6px; text-transform:uppercase; opacity:.9;">
            business DATA EDGE
          </div>
          <div style="font-size:20px; font-weight:900; margin-top:6px;">
            ${esc(theme || "business Data Edge")}
          </div>
        </div>

        <!-- Body -->
        <div style="background:${EDGE_BG}; padding:14px;">
          <div style="color:#111; font-size:14px; line-height:1.7;">
            ${esc(business )}
          </div>

          <!-- Pills -->
          <div style="margin-top:14px;">
            <span style="display:inline-block; background:#fff; border:1px solid ${BORDER}; padding:8px 12px; border-radius:999px; margin-right:10px; font-weight:700; font-size:13px;">
              7-day trial: <span style="color:${RED}; font-weight:900;">${esc(BRAND.trialCode)}</span>
            </span>

            <span style="display:inline-block; background:#fff; border:1px solid ${BORDER}; padding:8px 12px; border-radius:999px; font-weight:700; font-size:13px; color:${NAVY};">
              Investor-grade data
            </span>
          </div>

          <!-- Embedded CTA -->
          <div style="text-align:center; margin:18px 0 6px;">
            <div style="font-size:15px; color:${MUTED}; margin-bottom:10px;">
              Want the list for your market?
            </div>

            <a href="mailto:${BRAND.email}?subject=${encodeURIComponent(cta)}"
               style="display:inline-block; background:${BLUE}; color:#fff; padding:12px 18px; border-radius:12px; font-weight:900; text-decoration:none;">
              ${esc(cta)}
            </a>

            <div style="font-size:12px; color:${MUTED}; margin-top:10px;">
              Tip: reply with <b>keyword + County + State</b> so we can send the right export.
            </div>
          </div>

        </div>
      </td>
    </tr>
  </table>
`;
// ===== Signature =====
const signatureHtml = `
  <table role="presentation" width="100%" cellpadding="0" celbusiness acing="0" style="border-top:1px solid ${BORDER}; border-bottom:1px solid ${BORDER}; margin-top:22px;">
    <tr>
      <td style="padding:18px 0;">
        <table role="presentation" cellpadding="0" celbusiness acing="0">
          <tr>
            <td width="72" valign="middle" style="padding-right:14px;">
              ${
                BRAND.profileImg
                  ? `<img src="${BRAND.profileImg}" width="64" height="64" alt="business Data"
                          style="display:block; border-radius:999px; border:3px solid #dfe7ff; object-fit:cover;" />`
                  : `<div style="width:64px; height:64px; border-radius:999px; background:#eef2ff; border:3px solid #dfe7ff;"></div>`
              }
            </td>
            <td valign="middle" style="font-family:Arial, sans-serif;">
              <div style="color:${MUTED}; font-size:13px; margin-bottom:2px;">Sincerely,</div>
              <div style="font-size:20px; font-weight:900; margin-bottom:4px;">${esc(BRAND.signatureName)}</div>
              <div style="font-size:13px; color:${MUTED};">${esc(BRAND.signatureTitle)}</div>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
`;
const socialsHtml = `
  <table border="0" cellpadding="0" celbusiness acing="0" width="100%" style="mso-line-height-rule: exactly;">
    <tr>
      <td align="center" style="padding:16px 0 4px; mso-line-height-rule: exactly;">
        <table border="0" cellpadding="0" celbusiness acing="0" style="mso-line-height-rule: exactly;">
          <tr>
            <td align="center" valign="middle" width="24" style="padding:0 8px;">
              <a href="${BRAND.instagram}" target="_blank">
                <img src="https://cdn-images.mailchimp.com/icons/social-block-v2/color-instagram-48.png"
                     alt="Instagram" width="24" height="24"
                     style="display:block; border:0; outline:none; text-decoration:none; -ms-interpolation-mode:bicubic;" />
              </a>
            </td>

            <td align="center" valign="middle" width="24" style="padding:0 8px;">
              <a href="${BRAND.youtube}" target="_blank">
                <img src="https://cdn-images.mailchimp.com/icons/social-block-v2/color-youtube-48.png"
                     alt="YouTube" width="24" height="24"
                     style="display:block; border:0; outline:none; text-decoration:none; -ms-interpolation-mode:bicubic;" />
              </a>
            </td>
            <td align="center" valign="middle" width="24" style="padding:0 8px;">
            <a href="${BRAND.skool}" target="_blank">
              <img src="https://www.google.com/s2/favicons?domain=skool.com&sz=64"
         alt="Skool" width="24" height="24"
         style="display:block; border:0; outline:none; text-decoration:none; -ms-interpolation-mode:bicubic;" />
            </a>
            </td>
          </tr>
        </table>

        <div style="font-size:12px; color:${MUTED}; margin-top:10px; font-family:Arial, sans-serif;">
          Follow us for daily investor data + deal signals
        </div>
      </td>
    </tr>
  </table>
`;

const year = new Date().getFullYear();

const footerLegalHtml = `
  <div style="text-align:center; padding:16px 0 6px; color:${MUTED}; font-size:12px; line-height:1.7; font-family:Arial, sans-serif;">
    <div style="font-style:italic;">
      Copyright © ${year} ${esc(BRAND.name)}, All rights reserved.
    </div>

    <div style="margin-top:10px;">Want to change how you receive these emails?</div>

    <div>
      <a href="${BRAND.contact}" target="_blank" style="color:${BLUE}; text-decoration:none;">Update preferences</a>
      &nbsp;or&nbsp;
      <a href="mailto:${BRAND.email}?subject=Unsubscribe" style="color:${BLUE}; text-decoration:none;">unsubscribe</a>
    </div>

    <div style="margin-top:12px;">
      <a href="${BRAND.site}" target="_blank" style="color:${BLUE}; text-decoration:none;">${esc(BRAND.site)}</a>
      &nbsp;•&nbsp;
      <a href="mailto:${BRAND.email}" style="color:${BLUE}; text-decoration:none;">${esc(BRAND.email)}</a>
      &nbsp;•&nbsp;
      <a href="tel:+14092409010" style="color:${MUTED}; text-decoration:none;">${esc(BRAND.phone)}</a>
    </div>
  </div>
`;

// ===== Final HTML =====
const html = `
<div style="background:${BG}; padding:24px 10px;">
  <div style="max-width:720px; margin:0 auto; background:#ffffff; border-radius:20px; overflow:hidden; border:1px solid ${BORDER}; font-family:Arial, sans-serif;">

    ${topBarHtml}

    <div style="padding:18px; text-align:center; background:#ffffff;">
      <img src="${BRAND.logoUrl}" alt="${esc(BRAND.name)}" style="max-width:100%; height:auto; display:block; margin:0 auto;">
    </div>

    <hr style="border:none; border-top:1px solid ${BORDER}; margin:0;"/>

    <div style="padding:18px 18px;">
      <div style="font-size:14px; color:${MUTED};">Hi there,</div>

      <div style="font-size:15px; line-height:1.75; margin-top:10px; color:#111;">
        ${esc(intro)}
      </div>

      <hr style="border:none; border-top:1px solid ${BORDER}; margin:18px 0;"/>

      <div style="font-size:20px; font-weight:900; margin-bottom:10px;">Today’s Signals</div>

      ${itemCards}

      ${business Box}

      ${signatureHtml}

      ${socialsHtml}

      ${footerLegalHtml}
    </div>
  </div>
</div>
`;

return [{ json: { subject, html } }];
